//! ComixOS - A multi-architecture operating system kernel
//!
//! This is the main crate for ComixOS, an operating system kernel written in Rust
//! for RISC-V and LoongArch architectures. It provides basic OS functionalities
//! including memory management, process scheduling, and system call handling.

#![no_std]
#![no_main]
#![feature(custom_test_frameworks)]
// 下列特性在 nightly-2025-10-28 已稳定，但本项目固定的 nightly-2025-01-18
// (1.86-nightly，与评测机/参考项目 SanktaOS 对齐) 仍需显式开启。
#![feature(let_chains)]
#![feature(trait_upcasting)]
#![feature(unsigned_is_multiple_of)]
#![feature(ip_from)]
#![test_runner(test_runner)]
#![reexport_test_harness_main = "test_main"]

extern crate alloc;

// === 基础层（始终编译） ===
mod arch;
mod config;
mod console;
mod kernel;
mod sync;
mod test;

// 轻量工具模块（仅依赖基础层）
mod uapi;
mod util;

// 日志模块：console 在 device 不可用时回退到 arch 路径
#[macro_use]
mod log;

mod device;
mod fs;
mod ipc;
mod mm;
mod net;
mod security;
mod vfs;

use crate::arch::Platform;
use core::panic::PanicInfo;
#[cfg(test)]
use test::test_runner;

/// Rust 内核主入口点
///
/// 这是从汇编代码跳转到的第一个 Rust 函数。它负责初始化内核的所有子系统,
/// 包括内存管理、中断处理、定时器和任务调度器。
///
/// # Safety
///
/// 此函数标记为 `#[unsafe(no_mangle)]` 以确保链接器可以找到它。
/// 它必须从正确初始化的汇编入口点调用。
#[unsafe(no_mangle)]
pub extern "C" fn rust_main(_hartid: usize) -> ! {
    arch::boot::main(_hartid);
    unreachable!("Unreachable in rust_main()");
}

#[panic_handler]
fn panic(info: &PanicInfo) -> ! {
    if let Some(location) = info.location() {
        crate::console::emergency_print(format_args!(
            "Panicked at {}:{} {}\n",
            location.file(),
            location.line(),
            info.message()
        ));
    } else {
        crate::console::emergency_print(format_args!("Panicked: {}\n", info.message()));
    }

    crate::arch::ArchImpl::power_off()
}

//! Arch trait — 顶层架构抽象
//!
//! 组合 `CpuOps + VirtualMemory`，并添加进程管理、信号处理、
//! 用户/内核内存复制等高层 CPU/MMU 操作。
//!
//! 平台级操作（控制台 I/O、电源管理、地址映射）已移至 [`crate::arch::Platform`]。
//!
//! 注意：此 trait 使用关联类型来避免直接引用内核数据结构，
//! 确保架构层与内核其余部分的解耦。

use core::fmt::Debug;

use crate::{
    arch::{address::UA, cpu_ops::CpuOps, task::ExecStackLayout, virtual_memory::VirtualMemory},
    kernel::syscall::syscall_frame::SyscallFrame,
    mm::page_table::PagingError,
    uapi::signal::MContextT,
};

/// 架构陷阱帧的统一接口。
pub trait HwTrapFrame: Copy + Debug + Send + Sync + SyscallFrame + 'static {
    fn zero_init() -> Self;
    fn set_kernel_trap_frame(&mut self, entry: usize, terminal: usize, kernel_sp: usize);
    fn set_exec_trap_frame_from_layout(
        &mut self,
        entry: usize,
        kernel_sp: usize,
        layout: &ExecStackLayout,
    );
    unsafe fn set_clone_trap_frame(
        &mut self,
        parent_frame: &Self,
        kernel_sp: usize,
        user_sp: usize,
    );
    unsafe fn set_fork_trap_frame(&mut self, parent_frame: &Self);
    fn get_sp(&self) -> usize;
    fn set_sp(&mut self, val: usize);
    fn set_a0(&mut self, val: usize);
    fn set_a1(&mut self, val: usize);
    fn set_a2(&mut self, val: usize);
    fn set_ra(&mut self, val: usize);
    fn set_sepc(&mut self, pc: usize);
    fn get_sepc(&self) -> usize;
    fn set_tls(&mut self, tls: usize);
    fn to_mcontext(&self) -> MContextT;
    fn restore_from_mcontext(&mut self, mcontext: &MContextT);
}

/// 顶层架构抽象 trait。
///
/// 组合了 `CpuOps` 和 `VirtualMemory`，并添加了进程管理、信号处理、
/// 用户/内核内存复制、时间、IPI 等架构级操作。
///
/// # 移植要点
///
/// 这是移植新架构时需要实现的第三个 trait（在 `CpuOps` 和 `VirtualMemory` 之后）。
/// [`Platform`] 应同时实现以覆盖控制台、电源等平台操作。
///
/// [`Platform`]: crate::arch::Platform
pub trait Arch: CpuOps + VirtualMemory {
    /// 用户上下文类型（保存/恢复寄存器状态）
    type UserContext: Sized + Send + Sync + Clone;

    /// 硬件陷阱帧类型。
    type TrapFrame: HwTrapFrame;

    // ---- 进程 / 上下文切换 ----

    /// 创建新的用户上下文（设置入口点和栈顶）
    fn new_user_context(entry_point: usize, stack_top: usize) -> Self::UserContext;

    /// 上下文切换到指定用户上下文
    ///
    /// 保存当前执行上下文，恢复 `new_ctx` 的执行。
    ///
    /// # Safety
    ///
    /// 调用者必须确保 `new_ctx` 指向有效的用户上下文。
    unsafe fn context_switch(old: *mut Self::UserContext, new: *const Self::UserContext);

    // ---- 用户/内核内存复制 ----

    /// 从用户空间复制数据到内核空间
    ///
    /// # Safety
    ///
    /// - `src` 必须是有效的用户空间虚拟地址
    /// - `dst` 必须指向足够大的内核缓冲区
    /// - `len` 字节必须在合法范围内
    unsafe fn copy_from_user(src: UA, dst: *mut u8, len: usize) -> Result<(), PagingError>;

    /// 尝试从用户空间复制数据（非阻塞版本，不处理缺页）
    ///
    /// # Safety
    /// 同上
    unsafe fn try_copy_from_user(src: UA, dst: *mut u8, len: usize) -> Result<(), PagingError>;

    /// 从内核空间复制数据到用户空间
    ///
    /// # Safety
    ///
    /// - `dst` 必须是有效的用户空间虚拟地址
    /// - `src` 必须指向有效内核数据
    /// - `len` 字节必须在合法范围内
    unsafe fn copy_to_user(src: *const u8, dst: UA, len: usize) -> Result<(), PagingError>;

    /// 从用户空间复制以 '\0' 结尾的字符串
    ///
    /// # Safety
    /// 同上
    unsafe fn copy_strn_from_user(
        src: UA,
        dst: *mut u8,
        max_len: usize,
    ) -> Result<usize, PagingError>;

    // ---- 系统信息 ----

    /// 架构名称（如 "riscv64", "loongarch64"）
    fn name() -> &'static str;

    /// CPU 核心数量
    fn cpu_count() -> usize;

    // ---- 任务切换辅助 ----

    /// 任务切换时更新 trap frame 中的 CPU 指针
    ///
    /// 当任务在不同 CPU 之间迁移时，需要更新 trap frame 中的 `cpu_ptr` 字段，
    /// 确保 trap_entry 恢复正确的 tp 寄存器值。
    fn on_task_switch(trap_frame_ptr: usize, cpu_ptr: usize);

    // ---- 时间接口 ----

    /// 获取系统节拍计数
    fn get_ticks() -> usize;

    /// 获取系统启动以来的时间（节拍数）
    fn get_time() -> usize;

    /// 获取系统启动以来的时间（毫秒）
    fn get_time_ms() -> usize;

    /// 获取时钟频率（Hz）
    fn clock_freq() -> usize;

    // ---- IPI ----

    /// 向目标 CPU 发送重调度 IPI
    fn send_reschedule_ipi(target_cpu: usize);
}

//! 体系结构相关的模块
//!
//! 包含与特定处理器架构相关的实现。
//! 根据目标架构选择性地包含不同的子模块。
//!
//! # 分层约定
//!
//! 为了减少在 `arch/` 之外散落的 `cfg(target_arch = ...)` 与架构特定依赖：
//! - **架构条件编译应尽量集中在本模块**（选择 `riscv/` 或 `loongarch/`）。
//! - `arch/` 外部代码应通过 `crate::arch::*` 暴露的统一接口/钩子访问架构差异，
//!   避免直接依赖 `riscv`、`loongArch64` 等架构专用 crate 或寄存器操作。

// ---- trait 定义 ----

pub mod abi;
pub mod address;
pub mod arch;
pub mod cpu_ops;
pub mod plat;
pub mod task;
pub mod virtual_memory;

pub use arch::{Arch, HwTrapFrame};
pub use cpu_ops::CpuOps;
pub use plat::Platform;

// ---- 共享模块（架构无关） ----

mod arch_impl;
mod memory_impl;

// ---- 目标架构：RISC-V / LoongArch ----

#[cfg(target_arch = "loongarch64")]
mod loongarch;

#[cfg(target_arch = "riscv64")]
mod riscv;

#[cfg(target_arch = "loongarch64")]
#[allow(unused_imports)]
pub use loongarch::{
    boot, compiler_builtins, constant, cpu_ops as target_cpu_ops, intr, ipi, kernel, lib, memory,
    mm, platform, timer, trap,
};

#[cfg(target_arch = "riscv64")]
#[allow(unused_imports)]
pub use riscv::{
    boot, constant, cpu_ops as target_cpu_ops, intr, ipi, kernel, lib, memory, mm, platform, timer,
    trap,
};

// ---- 非目标架构（宿主测试）：Mock Stubs ----

#[cfg(not(any(target_arch = "riscv64", target_arch = "loongarch64")))]
mod mock;

#[cfg(not(any(target_arch = "riscv64", target_arch = "loongarch64")))]
#[allow(unused_imports)]
pub use mock::{
    MockAddressSpace, MockArch, MockCpuOps, boot, constant, intr, ipi, kernel, lib, mm, platform,
    timer, trap,
};

pub type TrapFrame = <ArchImpl as Arch>::TrapFrame;
pub use constant::SUPERVISOR_EXTERNAL;

// ---- ArchImpl 类型别名 ----
// 内核其余部分通过 ArchImpl 访问架构特定功能，无需关心具体架构。
#[cfg(target_arch = "riscv64")]
pub use riscv::cpu_ops::Riscv64 as ArchImpl;

#[cfg(target_arch = "loongarch64")]
pub use loongarch::cpu_ops::LoongArch64 as ArchImpl;

// 宿主（非目标架构）使用 Mock 实现
#[cfg(not(any(target_arch = "riscv64", target_arch = "loongarch64")))]
pub use crate::arch::mock::MockArch as ArchImpl;

// ---- PlatformImpl 类型别名 ----
// 与 ArchImpl 对应，内核其余部分通过 PlatformImpl 访问平台功能。

#[cfg(target_arch = "riscv64")]
pub use riscv::cpu_ops::Riscv64 as PlatformImpl;

#[cfg(target_arch = "loongarch64")]
pub use loongarch::cpu_ops::LoongArch64 as PlatformImpl;

#[cfg(not(any(target_arch = "riscv64", target_arch = "loongarch64")))]
pub use crate::arch::mock::MockArch as PlatformImpl;

// ---- 便捷包装函数 ----
// 将 Arch / Platform trait 方法暴露为普通函数。

/// 启用中断
#[inline]
pub fn enable_interrupts() {
    ArchImpl::enable_interrupts()
}

/// 当前中断是否处于启用状态
#[inline]
pub fn interrupts_enabled() -> bool {
    ArchImpl::interrupts_enabled()
}

/// 禁用中断并返回之前的中断状态
#[inline]
pub fn disable_interrupts() -> usize {
    ArchImpl::disable_interrupts()
}

#[inline]
pub unsafe fn read_and_disable_interrupts() -> usize {
    ArchImpl::disable_interrupts()
}

/// 恢复中断状态
#[inline]
pub fn restore_interrupt_state(flags: usize) {
    ArchImpl::restore_interrupt_state(flags)
}

#[inline]
pub unsafe fn restore_interrupts(flags: usize) {
    ArchImpl::restore_interrupt_state(flags)
}

#[inline]
pub fn interrupt_was_enabled(flags: usize) -> bool {
    ArchImpl::interrupt_was_enabled(flags)
}

#[inline]
pub fn are_interrupts_enabled() -> bool {
    ArchImpl::interrupts_enabled()
}

#[inline]
pub fn enable_irq(irq: usize) {
    intr::enable_irq(irq)
}

/// 获取当前 CPU ID
#[inline]
pub fn cpu_id() -> usize {
    ArchImpl::id()
}

/// 任务切换时更新 trap frame CPU 指针
#[inline]
pub fn on_task_switch(trap_frame_ptr: usize, cpu_ptr: usize) {
    ArchImpl::on_task_switch(trap_frame_ptr, cpu_ptr)
}

/// 获取系统节拍
#[inline]
pub fn get_ticks() -> usize {
    ArchImpl::get_ticks()
}

/// 获取系统时间（节拍）
#[inline]
pub fn get_time() -> usize {
    ArchImpl::get_time()
}

/// 获取系统时间（毫秒）
#[inline]
pub fn get_time_ms() -> usize {
    ArchImpl::get_time_ms()
}

/// 获取时钟频率
#[inline]
pub fn clock_freq() -> usize {
    ArchImpl::clock_freq()
}

/// 发送重调度 IPI
#[inline]
pub fn send_reschedule_ipi(target: usize) {
    ArchImpl::send_reschedule_ipi(target)
}

#[inline]
pub unsafe fn restore_trap_frame(trap_frame: &TrapFrame) {
    unsafe { trap::restore(trap_frame) }
}

#[inline]
pub unsafe fn set_trap_frame_cpu_ptr(trap_frame_ptr: *mut TrapFrame, cpu_ptr: usize) {
    unsafe { trap::set_trap_frame_cpu_ptr(trap_frame_ptr, cpu_ptr) }
}

#[inline]
pub unsafe fn init_kernel_trap_frame(
    trap_frame_ptr: *mut TrapFrame,
    entry: usize,
    terminal: usize,
    kernel_sp: usize,
) {
    unsafe {
        core::ptr::write(trap_frame_ptr, <TrapFrame as HwTrapFrame>::zero_init());
        <TrapFrame as HwTrapFrame>::set_kernel_trap_frame(
            &mut *trap_frame_ptr,
            entry,
            terminal,
            kernel_sp,
        );
        let cpu_ptr = {
            let _guard = crate::sync::PreemptGuard::new();
            crate::kernel::current_cpu() as *const _ as usize
        };
        set_trap_frame_cpu_ptr(trap_frame_ptr, cpu_ptr);
    }
}

#[inline]
pub fn sigreturn_trampoline_address() -> usize {
    trap::sigreturn_trampoline_address()
}

#[inline]
pub fn kernel_sigreturn_trampoline_bytes() -> &'static [u8] {
    trap::kernel_sigreturn_trampoline_bytes()
}

#[inline]
pub unsafe fn forkret_restore(tf_ptr: *mut TrapFrame, is_kernel_thread: bool) {
    unsafe { kernel::task::forkret_restore(tf_ptr, is_kernel_thread) }
}

#[inline]
pub unsafe fn prepare_user_restore(
    tfp: *mut TrapFrame,
    user_pc: address::VA,
    user_sp: address::VA,
) {
    unsafe { kernel::task::prepare_user_restore(tfp, user_pc, user_sp) }
}

/// 物理地址 → 虚拟地址（直接映射）
#[inline]
pub fn pa_to_va(pa: address::PA) -> address::VA {
    PlatformImpl::pa_to_va(pa)
}

/// MMIO 物理地址 → 虚拟地址。
///
/// 普通 RAM 直映和 MMIO 直映在部分架构上使用不同窗口。LoongArch 使用
/// DMW0 访问 uncached MMIO，避免把设备寄存器放进 DMW1 cached RAM 窗口。
#[inline]
pub fn mmio_pa_to_va(pa: address::PA) -> address::VA {
    #[cfg(target_arch = "loongarch64")]
    {
        address::VA::from_usize(pa.as_usize() | constant::DMW0_BASE)
    }

    #[cfg(not(target_arch = "loongarch64"))]
    {
        pa_to_va(pa)
    }
}

/// 虚拟地址 → 物理地址（直接映射）
///
/// # Safety
/// 调用者需确保 `va` 处于直接映射区域。
#[inline]
pub unsafe fn va_to_pa(va: address::VA) -> address::PA {
    unsafe { PlatformImpl::va_to_pa(va) }
}

/// 判断虚拟地址是否位于直接映射区域。
#[inline]
pub fn is_direct_mapped_va(va: address::VA) -> bool {
    va.as_usize() >= <PlatformImpl as virtual_memory::VirtualMemory>::PAGE_OFFSET
}

//! 系统调用模块
//!
//! 提供系统调用的实现

#![allow(dead_code)]
mod cred;
pub mod dispatch;
mod fcntl;
mod fs;
pub mod io;
mod ioctl;
mod ipc;
mod mm;
mod network;
pub mod numbers;
mod signal;
mod sys;
pub mod syscall_frame;
mod task;
mod util;

use core::ffi::{c_char, c_int, c_uint, c_ulong, c_void};

use crate::{
    impl_syscall,
    uapi::{
        fs::LinuxStatFs,
        futex::RobustListHead,
        iovec::IoVec,
        ipc::{KeyT, ShmIdDs},
        resource::{Rlimit, Rusage},
        sched::SchedParam,
        signal::{SigInfoT, SignalAction},
        sysinfo::SysInfo,
        time::{Itimerval, TimeSpec, Tms, timeval, timezone},
        types::{SigSetT, SizeT, StackT},
        uts_namespace::UtsNamespace,
    },
    vfs::{Stat, Statx},
};
use cred::*;
use fcntl::*;
use fs::*;
use io::*;
use ioctl::*;
use ipc::*;
use mm::*;
use network::*;
use signal::*;
use sys::*;
use task::*;

// 系统调用实现注册
// 分类顺序与 arch/riscv/syscall/syscall_number.rs 保持一致

// 文件系统/目录操作 (Filesystem/Directory Operations)
impl_syscall!(sys_getcwd, getcwd, (*mut u8, usize));

// Epoll & Duplication
impl_syscall!(sys_dup, dup, (usize));
impl_syscall!(sys_dup3, dup3, (usize, usize, u32));
impl_syscall!(sys_fcntl, fcntl, (usize, i32, usize));
impl_syscall!(sys_ioctl, ioctl, (i32, u32, usize));

// 文件/目录创建与链接 (File/Directory Creation and Linking)
impl_syscall!(sys_mknodat, mknodat, (i32, *const c_char, u32, u64));
impl_syscall!(sys_mkdirat, mkdirat, (i32, *const c_char, u32));
impl_syscall!(sys_unlinkat, unlinkat, (i32, *const c_char, u32));
impl_syscall!(
    sys_symlinkat,
    symlinkat,
    (*const c_char, i32, *const c_char)
);
impl_syscall!(
    sys_linkat,
    linkat,
    (i32, *const c_char, i32, *const c_char, u32)
);

// 挂载/文件系统信息 (Mount/Filesystem Info)
impl_syscall!(sys_statfs, statfs, (*const c_char, *mut LinuxStatFs));

// 文件大小/权限/所有权 (File Size/Permissions/Ownership)
impl_syscall!(sys_faccessat, faccessat, (i32, *const c_char, i32, u32));
impl_syscall!(sys_chdir, chdir, (*const c_char));
impl_syscall!(sys_fchmodat, fchmodat_legacy, (i32, *const c_char, u32));
impl_syscall!(sys_fchownat, fchownat, (i32, *const c_char, u32, u32, u32));

// 文件描述符操作 (File Descriptor Operations)
impl_syscall!(sys_openat, openat, (i32, *const c_char, u32, u32));
impl_syscall!(sys_close, close, (usize));
impl_syscall!(sys_pipe2, pipe2, (*mut i32, u32));
impl_syscall!(sys_getdents64, getdents64, (usize, *mut u8, usize));
impl_syscall!(sys_lseek, lseek, (usize, isize, usize));
impl_syscall!(sys_ftruncate, ftruncate, (usize, i64));

// I/O 操作 (Input/Output Operations)
impl_syscall!(sys_read, read, (usize, *mut u8, usize));
impl_syscall!(sys_write, write, (usize, *const u8, usize));
impl_syscall!(sys_readv, readv, (usize, *const IoVec, usize));
impl_syscall!(sys_writev, writev, (usize, *const IoVec, usize));
impl_syscall!(sys_pread64, pread64, (usize, *mut u8, usize, i64));
impl_syscall!(sys_pwrite64, pwrite64, (usize, *const u8, usize, i64));
impl_syscall!(sys_preadv, preadv, (usize, *const IoVec, usize, i64));
impl_syscall!(sys_pwritev, pwritev, (usize, *const IoVec, usize, i64));
impl_syscall!(sys_sendfile, sendfile, (usize, usize, *mut i64, usize));
impl_syscall!(
    sys_pselect6,
    pselect6,
    (usize, usize, usize, usize, usize, usize)
);
impl_syscall!(sys_ppoll, ppoll, (usize, usize, usize, usize));
impl_syscall!(sys_poll, poll, (usize, usize, i32));

// 文件元数据与同步 (File Metadata and Synchronization)
impl_syscall!(
    sys_readlinkat,
    readlinkat,
    (i32, *const c_char, *mut u8, usize)
);
impl_syscall!(
    sys_newfstatat,
    newfstatat,
    (i32, *const c_char, *mut Stat, u32)
);
impl_syscall!(sys_statx, statx, (i32, *const c_char, u32, u32, *mut Statx));
impl_syscall!(sys_fstat, fstat, (usize, *mut Stat));
impl_syscall!(sys_sync, sync, ());
impl_syscall!(sys_fsync, fsync, (usize));
impl_syscall!(sys_fdatasync, fdatasync, (usize));

// 定时器 (Timers)
impl_syscall!(
    sys_utimensat,
    utimensat,
    (i32, *const c_char, *const TimeSpec, u32)
);

// 进程与控制 (Process and Control)
impl_syscall!(sys_exit, exit, (c_int));
impl_syscall!(sys_exit_group, exit_group, noreturn, (c_int));
impl_syscall!(sys_set_tid_address, set_tid_address, (*mut c_int));

// 同步/休眠 (Synchronization/Sleeping)
impl_syscall!(sys_nanosleep, nanosleep, (*const TimeSpec, *mut TimeSpec));
impl_syscall!(
    sys_futex,
    futex,
    (*mut u32, c_int, u32, *const TimeSpec, *mut u32, u32)
);
impl_syscall!(
    sys_set_robust_list,
    set_robust_list,
    (*const RobustListHead, SizeT)
);
impl_syscall!(
    sys_get_robust_list,
    get_robust_list,
    (c_int, *mut *mut RobustListHead, *mut SizeT)
);
