/// 新创建的线程发生第一次调度时会从 forkret 开始执行。
pub(crate) fn forkret() {
    let (tf_ptr, is_kernel_thread) = {
        let _guard = crate::sync::PreemptGuard::new();
        let cpu = current_cpu();
        let task = cpu
            .current_task
            .as_ref()
            .expect("forkret: CPU has no current task")
            .clone();
        let t = task.lock();
        (
            t.trap_frame_ptr.load(Ordering::SeqCst),
            t.memory_space.is_none(),
        )
    };
    unsafe { crate::arch::forkret_restore(tf_ptr, is_kernel_thread) };
}

/// 在任务结束时调用的函数
/// 任务正常地执行完毕后通过创建时预先设置的寄存器跳转到该函数
/// 该函数不会返回，负责清理任务资源并切换到下一个任务
/// 参数:
/// * `code`: 任务的退出码
pub(crate) fn terminate_task(code: usize) -> ! {
    let task = {
        let _guard = crate::sync::PreemptGuard::new();
        let cpu = current_cpu();
        cpu.current_task.as_ref().unwrap().clone()
    };

    // 该函数目前仅用于处理“用户态致命异常”，默认行为应与 Linux 类似：
    // 终止整个进程（线程组），并唤醒父进程的 wait。
    let exit_code = code as i32;
    let (pid, is_process) = {
        let t = task.lock();
        (t.pid, t.is_process())
    };
    if is_process {
        cleanup_current_process_resources_on_exit();
        exit_process(task, exit_code);
    } else {
        // 当前为线程：找到线程组 leader（pid==tid）并终止整个进程
        let leader = TASK_MANAGER.lock().get_task(pid);
        if let Some(leader) = leader {
            if leader.lock().is_process() {
                cleanup_process_resources_on_exit(leader.clone());
                exit_process(leader, exit_code);
            } else {
                TASK_MANAGER.lock().exit_task(task, exit_code);
            }
        } else {
            TASK_MANAGER.lock().exit_task(task, exit_code);
        }
    }
    schedule();
    unreachable!("terminate_task: should not return after scheduled out terminated task");
}

/// 获取任务所属线程组的 leader。
pub fn task_group_leader(task: &SharedTask) -> Option<SharedTask> {
    let pid = task.lock().pid;
    TASK_MANAGER.lock().get_task(pid)
}

/// 进程退出时的资源清理（Linux 语义子集）：
/// - 释放用户地址空间（页表 + 用户映射）
/// - 关闭打开文件描述符（包括 socket fd）
///
/// 说明：
/// - 仅对“进程/线程组 leader”执行（`task.is_process()`），避免误伤线程共享资源。
/// - 必须先切换到内核页表，再释放当前进程页表资源。
pub fn cleanup_current_process_resources_on_exit() {
    let task = current_task();
    cleanup_process_resources_on_exit(task);
}

/// 清理指定进程/线程组 leader 持有的进程级资源。
pub fn cleanup_process_resources_on_exit(task: SharedTask) {
    if !task.lock().is_process() {
        return;
    }

    // 1) 先切换到全局内核页表，避免释放“正在使用的 satp”。
    if let Some(kernel_space) = crate::mm::get_global_kernel_space() {
        let _guard = crate::sync::PreemptGuard::new();
        current_cpu().switch_space(kernel_space);
    }

    // 2) 关闭所有 fd，并清理 socket 的 (tid,fd)->handle 映射，避免 fd 复用指向陈旧 handle。
    let tid = { task.lock().tid as usize };
    let fd_table = { task.lock().fd_table.clone() };
    let open = fd_table.take_all();
    for (fd, file) in open {
        if file
            .as_any()
            .downcast_ref::<crate::net::socket::SocketFile>()
            .is_some()
        {
            crate::net::socket::unregister_socket_fd(tid, fd);
        }
        drop(file);
    }

    // 3) 分离 SysV shared memory 映射，更新全局 registry 的 attach 计数。
    detach_all_shm(task.clone());

    // 4) 释放用户地址空间。
    task.lock().memory_space = None;
}

/// 分离一个进程持有的所有 SysV shared memory 映射。
///
/// 调用方可以在 exit/execve 清理路径中使用。该函数会先从 Task 中取走
/// attachment 元数据，再释放 task 锁后执行 munmap 和 registry 更新，避免
/// task -> address_space -> shm registry 的嵌套锁长期持有。
pub fn detach_all_shm(task: SharedTask) {
    let (pid, memory_space, attachment_table) = {
        let t = task.lock();
        (
            t.pid as c_int,
            t.memory_space.clone(),
            t.shm_attachments.clone(),
        )
    };

    let attachments = core::mem::take(&mut *attachment_table.lock());
    if attachments.is_empty() {
        return;
    }

    if let Some(memory_space) = memory_space {
        let mut space = memory_space.lock();
        for attachment in attachments.values() {
            if let Err(err) = space.munmap(VA::from_usize(attachment.addr), attachment.len) {
                crate::pr_warn!(
                    "detach_all_shm: failed to unmap shmid {} at 0x{:x}: {:?}",
                    attachment.segment.id,
                    attachment.addr,
                    err
                );
            }
        }
    }

    for attachment in attachments.values() {
        shm_detach_segment(&attachment.segment, pid);
    }
}

/// 尝试获取当前task
/// # 返回值：当前任务的SharedTask，如果没有则返回None
pub fn try_current_task() -> Option<SharedTask> {
    let _guard = crate::sync::PreemptGuard::new();
    current_cpu().current_task.as_ref().cloned()
}

/// 获取当前task
/// # 返回值：当前任务的SharedTask
/// # Panics：如果当前CPU没有任务则panic
pub fn current_task() -> SharedTask {
    match try_current_task() {
        Some(task) => task,
        None => {
            // 打印调用栈信息以便调试
            crate::pr_err!("current_task called with no current task!");
            crate::pr_err!("CPU ID: {}", crate::arch::cpu_id());
            panic!("current_task: CPU has no current task")
        }
    }
}

/// 获取当前任务的内存空间
/// # 返回值：当前任务的内存空间
pub fn current_memory_space() -> Arc<SpinLock<MemorySpace>> {
    let _guard = crate::sync::PreemptGuard::new();
    current_cpu()
        .current_memory_space
        .as_ref()
        .expect("current_memory_space: current task has no memory space")
        .clone()
}

/// 通知父任务子任务状态变化
/// # 参数：
/// * `task`: 子任务
pub fn notify_parent(task: SharedTask) {
    let ppid = {
        let t = task.lock();
        t.ppid
    };

    let t = TASK_MANAGER.lock();
    if let Some(p) = t.get_task(ppid) {
        // 1. 发送信号 (Wake up signal path)
        // 注意：send_signal 会短暂获取 p 锁
        t.send_signal(p.clone(), NUM_SIGCHLD);

        // 2. 唤醒等待队列 (WaitQueue path)
        // 必须显式唤醒，因为 sys_wait4 等待在 wait_child 上
        // 这里的关键是不能持有 p 锁调用 wake_up，否则死锁 (Recursive Parent Lock)
        let wait_child = p.lock().wait_child.clone();
        // 释放 p 锁 (t lock 也在 get_task 后如果 drop? 不，t held here)
        // t is TASK_MANAGER lock. p.lock() is Parent lock.
        // We hold TM lock. We hold Parent lock (briefly).
        // Then we hold WaitQueue lock.
        // wait_child.lock().wake_up_one() -> Locks Scheduler -> Locks Parent.
        // If we hold TM lock: TM -> WaitQueue -> Parent.
        // Is Parent -> TM possible? No.

        // So this is safe.
        wait_child.lock().wake_up_one();
    } else {
        // Parent not found (e.g. init process exiting), ignore
        let pid = task.lock().pid;
        crate::pr_warn!(
            "notify_parent: parent task {} not found for child {}",
            ppid,
            pid
        );
    }
}

/// 获取当前任务的文件描述符表
pub fn current_fd_table() -> Arc<FDTable> {
    current_task().lock().fd_table.clone()
}

/// 从当前任务的 FD 表中获取文件
pub fn get_file(fd: usize) -> Result<Arc<dyn File>, FsError> {
    current_fd_table().get(fd)
}

//！ 调度器模块
//!
//！ 定义了调度器接口和相关功能
mod rr_scheduler;
mod task_queue;
mod wait_queue;

use core::sync::atomic::{AtomicUsize, Ordering};

use crate::{
    arch::Arch,
    arch::kernel::context::Context,
    config::MAX_CPU_COUNT,
    kernel::{TaskState, TaskStruct, scheduler::rr_scheduler::RRScheduler, task::SharedTask},
    sync::SpinLock,
};

pub use task_queue::TaskQueue;
pub use wait_queue::WaitQueue;

/// Per-CPU 调度器数组
/// 每个 CPU 拥有独立的运行队列和调度器实例
static SCHEDULERS: [SpinLock<RRScheduler>; MAX_CPU_COUNT] =
    [const { SpinLock::new(RRScheduler::empty()) }; MAX_CPU_COUNT];

/// 负载均衡计数器
/// 用于简单轮转选择目标 CPU
static NEXT_CPU: AtomicUsize = AtomicUsize::new(0);

/// 上下文切换计划结构体
pub(crate) struct SwitchPlan {
    pub old: *mut Context,
    pub new: *const Context,
}

/// 调度器接口定义
/// 调度器负责决策和准备下一个任务的运行。
/// 具体来说，它负责以下几项工作：
/// 1. 决策： 根据优先级、时间片、调度策略等算法，从运行队列中选择下一个要执行的任务。
/// 2. 队列维护： 维护任务的运行队列（Run Queue）。
pub trait Scheduler {
    /// 构造函数
    fn new() -> Self;
    /// 添加任务到调度器
    /// 参数:
    /// * `task`: 需要添加的任务
    fn add_task(&mut self, task: SharedTask);
    /// 选择下一个要运行的任务
    /// # 返回值
    /// 如果要切换到下一个任务，返回切换计划 SwitchPlan；否则返回 None
    fn next_task(&mut self) -> Option<SwitchPlan>;
    /// 任务阻塞
    /// 修改任务状态并从运行队列中移除
    /// 参数:
    /// * `task`: 需要阻塞的任务
    /// * `receive_signal`: 是否可被信号中断
    /// 注意: 该函数仅设置状态，不负责切换任务
    fn sleep_task(&mut self, task: SharedTask, receive_signal: bool);
    /// 唤醒任务
    /// 修改任务状态并将其添加到运行队列
    /// 参数:
    /// * `task`: 需要唤醒的任务
    fn wake_up(&mut self, task: SharedTask);
    /// 任务终止
    /// 修改任务状态并从调度器中移除
    /// 参数:
    /// * `task`: 需要终止的任务
    fn exit_task(&mut self, task: SharedTask);
    /// 原子地检查条件并睡眠
    ///
    /// 在持有调度器锁和 task 锁的情况下执行 `prepare` 闭包。
    /// 如果 `prepare` 返回 `true`（条件满足，不需要睡眠），
    /// 则任务保持唤醒并返回 `false`。
    /// 如果 `prepare` 返回 `false`，则将任务设为睡眠态并从运行队列中移除，
    /// 返回 `true`。
    fn sleep_task_prepare(
        &mut self,
        task: SharedTask,
        receive_signal: bool,
        prepare: impl FnOnce(&mut crate::kernel::TaskStruct) -> bool,
    ) -> bool;
}

/// 获取当前 CPU 的调度器
pub fn current_scheduler() -> &'static SpinLock<RRScheduler> {
    let cpu_id = crate::arch::cpu_id();
    &SCHEDULERS[cpu_id]
}

/// 获取指定 CPU 的调度器
pub fn scheduler_of(cpu_id: usize) -> &'static SpinLock<RRScheduler> {
    &SCHEDULERS[cpu_id]
}

/// 通过轮询方式为新任务选择一个目标 CPU。
pub fn pick_cpu() -> usize {
    pick_cpu_from_mask(online_cpu_mask())
}

/// 在给定 CPU mask 内轮询选择目标 CPU。
pub fn pick_cpu_from_mask(mask: usize) -> usize {
    let online = online_cpu_mask();
    let mask = mask & online;
    if mask == 0 {
        return crate::arch::cpu_id().min(crate::kernel::num_cpu().saturating_sub(1));
    }

    let start = NEXT_CPU.fetch_add(1, Ordering::Relaxed);
    let num_cpu = crate::kernel::num_cpu();
    for offset in 0..num_cpu {
        let cpu = (start + offset) % num_cpu;
        if mask & (1usize << cpu) != 0 {
            return cpu;
        }
    }

    crate::arch::cpu_id().min(num_cpu.saturating_sub(1))
}

/// 当前在线 CPU 掩码。
///
/// 该内核的 RISC-V 配置上限是 `MAX_CPU_COUNT`，因此一个 `usize` 足够表达
/// sched affinity ABI 需要返回的在线 CPU 集。
pub fn online_cpu_mask() -> usize {
    let num_cpu = crate::kernel::num_cpu().min(usize::BITS as usize);
    if num_cpu == usize::BITS as usize {
        usize::MAX
    } else {
        (1usize << num_cpu) - 1
    }
}

/// 执行一次调度操作，切换到下一个任务
pub fn schedule() {
    // 读取并禁用中断，保护整个调度过程，并在返回时恢复原状态
    let flags = crate::arch::disable_interrupts();

    // 快速路径：如果运行队列为空且当前任务仍是 Running，就无需进入调度器
    let should_try_switch = {
        let sched = current_scheduler().lock();
        let rq_empty = sched.is_empty();
        drop(sched);

        let cur_running = {
            let cpu = crate::kernel::current_cpu();
            cpu.current_task
                .as_ref()
                .map(|t| t.lock().state == crate::kernel::TaskState::Running)
                .unwrap_or(false)
        };
        !(rq_empty && cur_running)
    };

    if should_try_switch {
        let plan = {
            let mut sched = current_scheduler().lock();
            // NOTE: next_task 内部会更新 current_task 与 current_memory_space 并切换页表
            sched.next_task()
        }; // 调度器锁在这里释放

        if let Some(plan) = plan {
            // SAFETY: next_task 生成的上下文指针有效
            unsafe { crate::arch::ArchImpl::context_switch(plan.old, plan.new) };
            // 通常不会立即返回；返回时再继续当前上下文后续逻辑
        }
    }

    // 恢复进入前的中断状态
    crate::arch::restore_interrupt_state(flags);
}

/// 主动放弃 CPU
/// 切换到下一个任务
/// 如果调用该函数的任务仍可运行，将被放回运行队列末尾，等待下一次调度
pub fn yield_task() {
    schedule();
}

/// 任务阻塞
/// 修改任务状态并从运行队列中移除
/// 参数:
/// * `task`: 需要阻塞的任务
/// * `receive_signal`: 是否可被信号中断
/// 注意: 该函数仅设置状态，不负责切换任务
pub fn sleep_task(task: SharedTask, receive_signal: bool) {
    let cpu_id = {
        let t = task.lock();
        t.on_cpu.unwrap_or_else(crate::arch::cpu_id)
    };
    scheduler_of(cpu_id).lock().sleep_task(task, receive_signal);
}

/// 唤醒任务
/// 修改任务状态并将其添加到运行队列
/// 参数:
/// * `task`: 需要唤醒的任务
pub fn wake_up_task(task: SharedTask) {
    let affinity = {
        let t = task.lock();
        t.cpu_affinity
    };
    let target_cpu = pick_cpu_from_mask(affinity);
    let current_cpu = crate::arch::cpu_id();
    let task_tid = { task.lock().tid };

    // 关键：多核下 wake 可能被重复触发（不同 CPU/不同事件源），必须做到“全局幂等”：
    // - 若任务已经是 Running（正在跑/已入队），则不要再次入队到其他 CPU 的运行队列
    // 否则同一任务可能被两个 CPU 同时调度运行，导致 TrapFrame/上下文被并发破坏（海森堡 panic/挂起）。
    let should_ipi;
    {
        let mut sched = scheduler_of(target_cpu).lock();

        // 用 task 锁串行化唤醒状态转换，避免跨 CPU 的“双重入队”
        {
            let mut t = task.lock();
            if t.state == TaskState::Running {
                return;
            }
            // Zombie/Stopped 不应被重新唤醒入队（保持现状，避免状态机混乱）
            if matches!(t.state, TaskState::Zombie | TaskState::Stopped) {
                return;
            }
            t.state = TaskState::Running;
            t.on_cpu = Some(target_cpu);
        }

        crate::pr_debug!(
            "[Scheduler] Waking up task {} on CPU {}",
            task_tid,
            target_cpu
        );
        sched.wake_up(task);
        should_ipi = target_cpu != current_cpu;
    }

    if should_ipi {
        crate::pr_debug!(
            "[Scheduler] Sending IPI from CPU {} to CPU {} for task {}",
            current_cpu,
            target_cpu,
            task_tid
        );
        crate::arch::send_reschedule_ipi(target_cpu);
    }
}

/// 任务终止
/// 修改任务状态并从调度器中移除
/// 参数:
/// * `task`: 需要终止的任务
pub fn exit_task(task: SharedTask) {
    let cpu_id = {
        let t = task.lock();
        t.on_cpu.unwrap_or_else(crate::arch::cpu_id)
    };
    scheduler_of(cpu_id).lock().exit_task(task);
}

/// 原子地检查条件并阻塞任务
///
/// 在持有调度器锁和 task 锁的情况下执行 `prepare` 闭包。
/// 如果 `prepare` 返回 `true`（条件满足），任务保持唤醒并返回 `false`。
/// 如果 `prepare` 返回 `false`，任务将被设为睡眠态并从运行队列移除，
/// 返回 `true`。
///
/// 这消除了 TOCTOU 竞态条件：条件检查和状态转换在锁内原子地完成。
pub fn sleep_task_prepare(
    task: SharedTask,
    receive_signal: bool,
    prepare: impl FnOnce(&mut TaskStruct) -> bool,
) -> bool {
    let cpu_id = {
        let t = task.lock();
        t.on_cpu.unwrap_or_else(crate::arch::cpu_id)
    };
    scheduler_of(cpu_id)
        .lock()
        .sleep_task_prepare(task, receive_signal, prepare)
}

//! 虚拟文件系统（VFS）层
//!
//! 该模块提供了一个 **POSIX 兼容的虚拟文件系统抽象**，支持多种文件类型和文件系统的统一访问。
//!
//! # 组件
//!
//! - [`mod@file`] - 会话层接口定义 (File trait)
//! - [`inode`] - 存储层接口定义 (Inode trait)
//! - [`dentry`] - 目录项结构和全局缓存
//! - [`path`] - 路径解析引擎（绝对/相对路径、符号链接）
//! - [`mount`] - 挂载表管理和挂载点栈
//! - [`fd_table`] - 进程级文件描述符表
//! - [`file_lock`] - POSIX 文件锁管理器
//! - [`file_system`] - 文件系统抽象接口
//! - [`impls`] - 具体文件类型实现（RegFile、PipeFile 等）
//! - [`error`] - VFS 错误类型定义
//! - [`dev`]/[`devno`] - 设备号管理和驱动注册
//!
//! # 设计概览
//!
//! ## 分层架构
//!
//! VFS 采用四层架构设计，从上到下依次为：
//!
//! 1. **应用层**：系统调用接口和文件描述符表 ([`FDTable`])
//! 2. **会话层**：有状态的文件操作接口 ([`File`] trait)，维护 offset 和 flags
//! 3. **路径层**：目录树管理和路径解析 ([`Dentry`]、[`path`] 模块)
//! 4. **存储层**：无状态的存储访问接口 ([`Inode`] trait)
//!
//! ## 核心设计理念
//!
//! ### 分离会话与存储
//!
//! - **会话层 (File)**：每次 `open()` 创建新的 `File` 实例，维护独立的 `offset` 和 `flags`
//! - **存储层 (Inode)**：多个 `File` 可共享同一个 `Inode`，实现硬链接和 dup 语义
//!
//! ```text
//! fd[3] ──┐
//!         ├──> Arc<RegFile> { offset: 100, ... }
//! fd[4] ──┘                     │
//!                               │
//!                               ▼
//!                          Arc<Dentry>
//!                               │
//!                               ▼
//!                          Arc<dyn Inode>
//! ```
//!
//! ### 目录项缓存
//!
//! - **全局缓存** ([`DENTRY_CACHE`])：路径 → `Weak<Dentry>` 映射，避免重复解析
//! - **树状缓存**：Dentry 内部维护父子关系，加速相对路径查找
//! - **自动失效**：使用 `Weak` 引用，不再使用的 Dentry 自动回收
//!
//! ### 挂载表管理
//!
//! - **最长前缀匹配**：访问 `/mnt/data/file` 时自动选择最匹配的挂载点
//! - **挂载点栈**：同一路径可多次挂载，最后挂载的文件系统覆盖前面的
//! - **全局单例** ([`MOUNT_TABLE`])：所有挂载点的集中管理
//!
//! ## 性能特点
//!
//! - **零拷贝读写**：RegFile 直接调用 Inode 的 `read_at`/`write_at`，无额外拷贝
//! - **原子偏移量**：使用 `AtomicUsize` 管理文件偏移，无锁并发读写
//! - **多级缓存**：Dentry 缓存、挂载点缓存减少重复查找
//! - **引用计数**：使用 `Arc`/`Weak` 自动管理对象生命周期，无需手动释放
//!
//! ## 并发安全
//!
//! - **FDTable**：内部使用 `SpinLock` 保护文件描述符数组
//! - **DentryCache**：使用 `SpinLock` 保护全局缓存
//! - **MountTable**：使用 `SpinLock` 保护挂载表
//! - **FileLockManager**：使用 `SpinLock` 保护文件锁表
//!
//! # 文件类型
//!
//! VFS 支持多种文件类型，所有类型都实现统一的 [`File`] trait：
//!
//! - [`RegFile`]: 普通文件 - 基于 Inode，支持 seek
//! - [`PipeFile`]: 管道文件 - 环形缓冲区，流式设备
//! - `StdinFile`/`StdoutFile`/`StderrFile`: 标准 I/O 文件
//! - `CharDevFile`: 字符设备文件（串口、终端等）
//! - `BlkDevFile`: 块设备文件（磁盘等）
//!
//! # 使用示例
//!
//! ## 基本文件操作
//!
//! ```rust
//! use vfs::{vfs_lookup, RegFile, OpenFlags};
//! use alloc::sync::Arc;
//!
//! // 1. 查找文件
//! let dentry = vfs_lookup("/etc/passwd")?;
//!
//! // 2. 创建 File 对象
//! let file = Arc::new(RegFile::new(dentry, OpenFlags::O_RDONLY));
//!
//! // 3. 读取数据
//! let mut buf = [0u8; 1024];
//! let n = file.read(&mut buf)?;
//! ```
//!
//! ## 使用文件描述符
//!
//! ```rust
//! // 分配文件描述符
//! let fd_table = current_task().lock().fd_table.clone();
//! let fd = fd_table.alloc(file)?;
//!
//! // 通过 FD 访问文件
//! let file = fd_table.get(fd)?;
//! file.read(&mut buf)?;
//!
//! // 关闭文件
//! fd_table.close(fd)?;
//! ```
//!
//! ## 挂载文件系统
//!
//! ```rust
//! use vfs::{MOUNT_TABLE, MountFlags};
//!
//! // 创建文件系统
//! let tmpfs = Arc::new(TmpFs::new());
//!
//! // 挂载到 /tmp
//! MOUNT_TABLE.mount(tmpfs, "/tmp", MountFlags::empty(), None)?;
//!
//! // 访问挂载点下的文件
//! let dentry = vfs_lookup("/tmp/test.txt")?;
//!
//! // 卸载
//! MOUNT_TABLE.umount("/tmp")?;
//! ```
//!
//! ## 创建管道
//!
//! ```rust
//! use vfs::PipeFile;
//!
//! let (read_file, write_file) = PipeFile::create_pipe()?;
//!
//! // 分配文件描述符
//! let read_fd = fd_table.alloc(read_file)?;
//! let write_fd = fd_table.alloc(write_file)?;
//!
//! // 父子进程通过管道通信
//! ```

