//! 文件抽象层 - VFS 会话层接口
//!
//! 该模块定义了统一的文件操作接口 [`File`] trait，支持普通文件、管道、字符设备等多种文件类型。
//! 所有打开的文件以 `Arc<dyn File>` 形式存储在进程的文件描述符表中。
//!
//! # 架构定位
//!
//! VFS 采用两层设计：
//! - **会话层**: [`File`] trait - 维护会话状态（offset、flags），有状态操作
//! - **存储层**: [`Inode`] trait - 提供无状态的随机访问
//!
//! ## 为什么分离会话层和存储层?
//!
//! 同一个文件可以被多次打开或 dup，每次打开都需要独立的会话状态（如 offset），
//! 但它们共享相同的底层存储（Inode）。这种设计支持：
//!
//! - **dup 语义**: 复制的文件描述符共享 offset
//! - **硬链接**: 多个路径指向同一个 Inode
//! - **fork 继承**: 父子进程共享文件表
//!
//! ```text
//! 进程 A: fd[3] ──┐
//!                 ├──> Arc<RegFile> { offset: 100 }
//! 进程 A: fd[4] ──┘          │
//!                            ▼
//!                       Arc<Dentry>
//!                            │
//!                            ▼
//!                       Arc<Inode> ←─── 进程 B: fd[5] -> Arc<RegFile> { offset: 200 }
//! ```
//!
//! # 实现类型
//!
//! - [`RegFile`](crate::vfs::RegFile) - 普通文件，基于 Inode，支持 seek
//! - [`PipeFile`](crate::vfs::PipeFile) - 管道，环形缓冲区，流式设备
//! - `StdinFile` / `StdoutFile` / `StderrFile` - 标准 I/O
//! - `CharDevFile` - 字符设备文件（串口、终端等）
//! - `BlkDevFile` - 块设备文件（磁盘等）
//!
//! # 设计特点
//!
//! ## 可选方法
//!
//! File trait 中的许多方法提供了默认实现（返回 `NotSupported`），
//! 允许不同文件类型只实现自己支持的功能：
//!
//! - `lseek()`: 仅 RegFile 和 BlkDevFile 支持
//! - `get_pipe_size()`: 仅 PipeFile 支持
//! - `ioctl()`: 仅设备文件支持
//!
//! ## 原子操作
//!
//! RegFile 使用 `AtomicUsize` 管理 offset，支持无锁并发读写：
//!
//! ```text
//! 线程 1: read() -> fetch_add(n)
//! 线程 2: read() -> fetch_add(m)  // 并发安全
//! ```
//!
//! # 使用示例
//!
//! ```rust
//! use vfs::{vfs_lookup, RegFile, OpenFlags, File};
//! use alloc::sync::Arc;
//!
//! // 1. 创建 File 对象
//! let dentry = vfs_lookup("/etc/passwd")?;
//! let file: Arc<dyn File> = Arc::new(
//!     RegFile::new(dentry, OpenFlags::O_RDONLY)
//! );
//!
//! // 2. 读取数据
//! let mut buf = [0u8; 1024];
//! let n = file.read(&mut buf)?;
//!
//! // 3. 检查文件属性
//! assert!(file.readable());
//! assert!(!file.writable());
//!
//! // 4. 获取元数据
//! let metadata = file.metadata()?;
//! println!("文件大小: {}", metadata.size);
//! ```

use crate::uapi::fcntl::{OpenFlags, SeekWhence};
use crate::vfs::{Dentry, DirEntry, FsError, Inode, InodeMetadata};
use alloc::{sync::Arc, vec::Vec};

/// 文件操作的统一接口
///
/// 所有打开的文件以 `Arc<dyn File>` 形式存储在进程的文件描述符表中。
///
/// # 设计要点
///
/// - 方法不携带 offset 参数，由实现者内部维护
/// - 支持可 seek 文件（RegFile）和流式设备（PipeFile）
/// - 可选方法提供默认实现（如 `lseek` 默认返回 `NotSeekable`）
pub trait File: Send + Sync {
    /// 检查文件是否可读
    fn readable(&self) -> bool;

    /// 检查文件是否可写
    fn writable(&self) -> bool;

    /// 从文件读取数据
    ///
    /// RegFile 从当前 offset 读取并更新 offset；
    /// PipeFile 从管道缓冲区读取，无 offset 概念。
    fn read(&self, buf: &mut [u8]) -> Result<usize, FsError>;

    /// 向文件写入数据
    ///
    /// RegFile 在 `O_APPEND` 模式下总是写到文件末尾。
    fn write(&self, buf: &[u8]) -> Result<usize, FsError>;

    /// 获取文件元数据
    fn metadata(&self) -> Result<InodeMetadata, FsError>;

    /// 设置文件偏移量（可选方法）
    ///
    /// 默认返回 `NotSeekable`，适用于流式设备。
    fn lseek(&self, _offset: isize, _whence: SeekWhence) -> Result<usize, FsError> {
        Err(FsError::NotSeekable)
    }

    /// 获取当前偏移量（可选方法）
    ///
    /// 默认返回 0，适用于流式设备。
    fn offset(&self) -> usize {
        0
    }

    /// 获取打开标志（可选方法）
    ///
    /// 用于 exec 时关闭 `O_CLOEXEC` 文件。
    fn flags(&self) -> OpenFlags {
        OpenFlags::empty()
    }

    /// 获取目录项（可选方法）
    ///
    /// 默认返回`FsError::NotSupported`,适用于RegFile
    fn dentry(&self) -> Result<Arc<Dentry>, FsError> {
        Err(FsError::NotSupported)
    }

    /// 获取Inode（可选方法）
    ///
    /// 默认返回`FsError::NotSupported`,适用于RegFile
    fn inode(&self) -> Result<Arc<dyn Inode>, FsError> {
        Err(FsError::NotSupported)
    }

    /// 读取目录项，可由有状态 File 实现缓存目录快照。
    fn readdir_cached(&self) -> Result<Arc<Vec<DirEntry>>, FsError> {
        Ok(Arc::new(self.inode()?.readdir()?))
    }

    /// 设置文件状态标志（可选方法，用于 F_SETFL）
    ///
    /// 默认返回 `NotSupported`，适用于不支持动态修改标志的文件类型
    fn set_status_flags(&self, _flags: OpenFlags) -> Result<(), FsError> {
        Err(FsError::NotSupported)
    }

    /// 获取管道大小（可选方法，用于 F_GETPIPE_SZ）
    ///
    /// 默认返回 `NotSupported`，仅适用于 PipeFile
    fn get_pipe_size(&self) -> Result<usize, FsError> {
        Err(FsError::NotSupported)
    }

    /// 设置管道大小（可选方法，用于 F_SETPIPE_SZ）
    ///
    /// 成功返回实际设置后的管道大小。默认返回 `NotSupported`，仅适用于 PipeFile。
    fn set_pipe_size(&self, _size: usize) -> Result<usize, FsError> {
        Err(FsError::NotSupported)
    }

    /// 获取异步 I/O 所有者（可选方法，用于 F_GETOWN）
    ///
    /// 返回接收 SIGIO 信号的进程 PID
    /// 默认返回 `NotSupported`
    fn get_owner(&self) -> Result<i32, FsError> {
        Err(FsError::NotSupported)
    }

    /// 设置异步 I/O 所有者（可选方法，用于 F_SETOWN）
    ///
    /// 设置接收 SIGIO 信号的进程 PID
    /// 默认返回 `NotSupported`
    fn set_owner(&self, _pid: i32) -> Result<(), FsError> {
        Err(FsError::NotSupported)
    }

    /// 从指定位置读取数据（可选方法，用于 pread64/preadv）
    ///
    /// 不改变文件偏移量，默认返回 `NotSupported`，适用于非 seekable 文件
    fn read_at(&self, _offset: usize, _buf: &mut [u8]) -> Result<usize, FsError> {
        Err(FsError::NotSupported)
    }

    /// 向指定位置写入数据（可选方法，用于 pwrite64/pwritev）
    ///
    /// 不改变文件偏移量，默认返回 `NotSupported`，适用于非 seekable 文件
    fn write_at(&self, _offset: usize, _buf: &[u8]) -> Result<usize, FsError> {
        Err(FsError::NotSupported)
    }

    /// 执行设备特定的控制操作（可选方法，用于 ioctl）
    ///
    /// 用于设备驱动程序特定的控制命令。
    /// - `request`: ioctl 请求码
    /// - `arg`: 参数指针（作为 usize 传递）
    ///
    /// 默认返回 `NotSupported`，仅由支持 ioctl 的设备类型实现
    fn ioctl(&self, _request: u32, _arg: usize) -> Result<isize, FsError> {
        Err(FsError::NotSupported)
    }

    /// 获取 Any trait 引用，用于安全的类型转换
    fn as_any(&self) -> &dyn core::any::Any;

    /// 从socket接收数据并获取源地址（可选方法，用于recvfrom）
    ///
    /// 返回(读取字节数, 源地址)
    /// 默认返回NotSupported，仅socket实现
    fn recvfrom(&self, _buf: &mut [u8]) -> Result<(usize, Option<alloc::vec::Vec<u8>>), FsError> {
        Err(FsError::NotSupported)
    }
}

//! Inode 抽象层 - VFS 存储层接口
//!
//! 该模块定义了文件系统的底层存储接口，提供无状态的文件和目录访问能力。
//!
//! # 组件
//!
//! - [`Inode`] trait：文件/目录的核心操作接口
//! - [`InodeMetadata`]：文件元数据（大小、权限、时间戳等）
//! - [`InodeType`]：文件类型枚举（普通文件、目录、符号链接等）
//! - [`FileMode`]：POSIX 兼容的权限位
//! - [`DirEntry`]：轻量级目录项（用于 readdir）
//!
//! # 与 File trait 的关系
//!
//! | 方面 | File (会话层) | Inode (存储层) |
//! |------|---------------|----------------|
//! | 状态 | 有状态 (offset、flags) | 无状态 |
//! | 方法 | `read(buf)` | `read_at(offset, buf)` |
//! | 实例 | 每次 open 创建新实例 | 多个 File 可共享同一 Inode |
//! | 职责 | 维护会话状态 | 提供存储访问 |
//!
//! ## 为什么 Inode 是无状态的?
//!
//! 无状态设计使得：
//! - 同一文件可被多次打开，各自维护独立的 offset
//! - 硬链接可以共享同一个 Inode
//! - 多线程读写时无需锁定 Inode（offset 由 File 管理）
//!
//! ```text
//! File { offset: 0 }  ──┐
//!                       ├──> Inode { data: [...] }
//! File { offset: 100 }──┘
//! ```
//!
//! # 设计要点
//!
//! ## 随机访问
//!
//! 所有读写方法都携带 `offset` 参数，支持真正的随机访问：
//!
//! ```rust
//! // 可以乱序访问，不影响彼此
//! inode.read_at(100, &mut buf1)?;  // 读取位置 100
//! inode.read_at(0, &mut buf2)?;    // 读取位置 0
//! ```
//!
//! ## 幂等性
//!
//! 读取操作应该是幂等的（多次调用返回相同结果）：
//!
//! ```rust
//! let n1 = inode.read_at(0, &mut buf)?;
//! let n2 = inode.read_at(0, &mut buf)?;
//! assert_eq!(n1, n2);  // 相同的读取结果
//! ```
//!
//! ## 目录操作
//!
//! Inode 不仅支持文件读写，还支持目录操作：
//!
//! - `lookup(name)` - 查找子项
//! - `create(name)` - 创建文件
//! - `mkdir(name)` - 创建目录
//! - `unlink(name)` - 删除文件
//! - `readdir()` - 列出目录内容
//!
//! # 使用示例
//!
//! ```rust
//! use vfs::{Inode, FileMode};
//!
//! // 1. 读写文件
//! let mut buf = [0u8; 512];
//! let n = inode.read_at(0, &mut buf)?;
//! inode.write_at(512, b"hello")?;
//!
//! // 2. 目录操作
//! let child_inode = parent_inode.lookup("file.txt")?;
//! parent_inode.create("new.txt", FileMode::S_IFREG | FileMode::S_IRUSR)?;
//!
//! // 3. 获取元数据
//! let metadata = inode.metadata()?;
//! println!("大小: {}, 类型: {:?}", metadata.size, metadata.inode_type);
//! ```

use core::any::Any;

use crate::uapi::time::TimeSpec;
use crate::vfs::{Dentry, FsError};
use alloc::string::String;
use alloc::sync::Arc;
use alloc::sync::Weak;
use alloc::vec::Vec;

/// 文件类型
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum InodeType {
    File,        // 普通文件
    Directory,   // 目录
    Symlink,     // 符号链接
    CharDevice,  // 字符设备
    BlockDevice, // 块设备
    Fifo,        // 命名管道
    Socket,      // 套接字
}

bitflags::bitflags! {
    #[derive(Debug, Clone, Copy, PartialEq, Eq)]
    /// 文件权限和类型（与 POSIX 兼容）
    pub struct FileMode: u32 {
        // 文件类型掩码
        const S_IFMT   = 0o170000;  // 文件类型掩码
        const S_IFREG  = 0o100000;  // 普通文件
        const S_IFDIR  = 0o040000;  // 目录
        const S_IFLNK  = 0o120000;  // 符号链接
        const S_IFCHR  = 0o020000;  // 字符设备
        const S_IFBLK  = 0o060000;  // 块设备
        const S_IFIFO  = 0o010000;  // FIFO
        const S_IFSOCK = 0o140000;  // Socket

        // 用户权限
        const S_IRUSR  = 0o400;     // 用户读
        const S_IWUSR  = 0o200;     // 用户写
        const S_IXUSR  = 0o100;     // 用户执行

        // 组权限
        const S_IRGRP  = 0o040;     // 组读
        const S_IWGRP  = 0o020;     // 组写
        const S_IXGRP  = 0o010;     // 组执行

        // 其他用户权限
        const S_IROTH  = 0o004;     // 其他读
        const S_IWOTH  = 0o002;     // 其他写
        const S_IXOTH  = 0o001;     // 其他执行

        // 特殊位
        const S_ISUID  = 0o4000;    // Set UID
        const S_ISGID  = 0o2000;    // Set GID
        const S_ISVTX  = 0o1000;    // Sticky bit
    }
}

impl FileMode {
    /// 检查是否有读权限（暂时只检查用户权限）
    pub fn can_read(&self) -> bool {
        self.contains(FileMode::S_IRUSR)
    }

    /// 检查是否有写权限
    pub fn can_write(&self) -> bool {
        self.contains(FileMode::S_IWUSR)
    }

    /// 检查是否有执行权限
    pub fn can_execute(&self) -> bool {
        self.contains(FileMode::S_IXUSR)
    }
}

/// 轻量级目录项（readdir 返回）
///
/// 用于数据传输，无引用关系，读取后即可丢弃
#[derive(Debug, Clone)]
pub struct DirEntry {
    pub name: String,          // 文件名
    pub inode_no: usize,       // Inode 编号
    pub inode_type: InodeType, // 文件类型
}

/// 文件元数据
#[derive(Debug, Clone)]
pub struct InodeMetadata {
    pub inode_no: usize,       // Inode 编号
    pub inode_type: InodeType, // 文件类型
    pub mode: FileMode,        // 权限位
    pub uid: u32,              // 用户 ID
    pub gid: u32,              // 组 ID
    pub size: usize,           // 文件大小（字节）
    pub atime: TimeSpec,       // 访问时间
    pub mtime: TimeSpec,       // 修改时间
    pub ctime: TimeSpec,       // 状态改变时间
    pub nlinks: usize,         // 硬链接数
    pub blocks: usize,         // 占用的块数（512B 为单位）
    pub rdev: u64,             // 设备号（仅对 CharDevice 和 BlockDevice 有效）
}

/// 文件系统底层存储接口
///
/// Inode 代表文件系统中的一个文件或目录，提供无状态的随机访问。
///
/// # 设计要点
///
/// - 所有读写方法必须携带 `offset` 参数（体现随机访问能力）
/// - 不维护会话状态（offset 由上层 File 维护）
/// - 支持目录操作（lookup、create、mkdir、unlink）
pub trait Inode: Send + Sync + Any {
    /// 获取文件元数据
    fn metadata(&self) -> Result<InodeMetadata, FsError>;

    /// 从指定偏移量读取数据
    ///
    /// 多次调用相同参数应返回相同结果（无副作用）。
    fn read_at(&self, offset: usize, buf: &mut [u8]) -> Result<usize, FsError>;

    /// 向指定偏移量写入数据
    fn write_at(&self, offset: usize, buf: &[u8]) -> Result<usize, FsError>;

    /// 在目录中查找子项
    ///
    /// 返回子项的 Inode。仅对目录有效。
    fn lookup(&self, name: &str) -> Result<Arc<dyn Inode>, FsError>;

    /// 在目录中创建文件
    fn create(&self, name: &str, mode: FileMode) -> Result<Arc<dyn Inode>, FsError>;

    /// 在目录中创建子目录
    fn mkdir(&self, name: &str, mode: FileMode) -> Result<Arc<dyn Inode>, FsError>;

    /// 创建符号链接
    fn symlink(&self, name: &str, target: &str) -> Result<Arc<dyn Inode>, FsError>;

    /// 创建硬链接
    fn link(&self, name: &str, target: &Arc<dyn Inode>) -> Result<(), FsError>;

    /// 删除普通文件/链接
    fn unlink(&self, name: &str) -> Result<(), FsError>;

    /// 删除目录
    fn rmdir(&self, name: &str) -> Result<(), FsError>;

    /// 重命名/移动 (原子操作)
    fn rename(
        &self,
        old_name: &str,
        new_parent: Arc<dyn Inode>,
        new_name: &str,
    ) -> Result<(), FsError>;

    /// 列出目录内容
    fn readdir(&self) -> Result<Vec<DirEntry>, FsError>;

    /// 截断文件到指定大小
    fn truncate(&self, size: usize) -> Result<(), FsError>;

    /// 同步文件数据到存储设备
    fn sync(&self) -> Result<(), FsError>;

    /// 设置 Dentry（可选方法）
    fn set_dentry(&self, _dentry: Weak<Dentry>) {}

    /// 获取 Dentry（可选方法）
    fn get_dentry(&self) -> Option<Arc<Dentry>> {
        None
    }

    /// 是否允许 VFS 缓存该节点的 dentry
    ///
    /// 对于像 procfs 这类“随时变化”的路径（例如 `/proc/[pid]`），缓存 dentry 可能导致
    /// 进程退出后仍能通过缓存路径访问到旧节点（幽灵条目）。此时应返回 false。
    fn cacheable(&self) -> bool {
        true
    }

    /// 向下转型为 &dyn Any，用于支持 downcast
    fn as_any(&self) -> &dyn Any;

    /// 设置文件时间戳
    fn set_times(&self, atime: Option<TimeSpec>, mtime: Option<TimeSpec>) -> Result<(), FsError>;

    /// 读取符号链接的目标路径
    fn readlink(&self) -> Result<String, FsError>;

    /// 创建设备文件节点
    fn mknod(&self, name: &str, mode: FileMode, dev: u64) -> Result<Arc<dyn Inode>, FsError>;

    /// 修改文件所有者和组
    ///
    /// # 参数
    /// * `uid` - 新的用户 ID（`u32::MAX` 表示不改变）
    /// * `gid` - 新的组 ID（`u32::MAX` 表示不改变）
    ///
    /// # 返回值
    /// * `Ok(())` - 成功
    /// * `Err(FsError)` - 失败
    ///
    /// # 在单 root 用户系统中的行为
    /// 此方法会更新 inode 的 uid/gid 字段，但不进行权限检查。
    /// 所有调用都会成功（除非文件系统错误）。
    fn chown(&self, _uid: u32, _gid: u32) -> Result<(), FsError>;

    /// 修改文件权限模式
    ///
    /// # 参数
    /// * `mode` - 新的权限模式（只修改权限位，不修改文件类型位）
    ///
    /// # 返回值
    /// * `Ok(())` - 成功
    /// * `Err(FsError)` - 失败
    ///
    /// # 在单 root 用户系统中的行为
    /// 此方法会更新 inode 的 mode 字段，但不进行权限检查。
    /// 所有调用都会成功（除非文件系统错误）。
    fn chmod(&self, _mode: FileMode) -> Result<(), FsError>;
}

/// 为 `Arc<dyn Inode>` 提供向下转型辅助方法
impl dyn Inode {
    /// 尝试向下转型为具体的 Inode 类型
    pub fn downcast_arc<T: Inode>(self: Arc<Self>) -> Result<Arc<T>, Arc<Self>> {
        if (*self).as_any().is::<T>() {
            // SAFETY: 已经通过 is::<T>() 检查了类型
            unsafe {
                let ptr = Arc::into_raw(self);
