/// Ext4 文件系统
pub struct Ext4FileSystem {
    /// 底层块设备驱动
    device: Arc<dyn BlockDriver>,

    /// 块大小
    block_size: usize,

    /// 总块数
    total_blocks: usize,

    /// 设备 ID
    device_id: usize,

    /// VFS clean page cache object id prefix.
    fs_id: u64,

    /// ext4_rs 文件系统对象
    ext4: Arc<Mutex<ext4_rs::Ext4>>,

    /// Shared clean file page cache.
    page_cache: Arc<PageCache>,

    /// 根 inode
    root: Arc<dyn Inode>,
}

impl Ext4FileSystem {
    /// 打开 Ext4 文件系统
    ///
    /// # 参数
    /// - `device`: 块设备驱动
    /// - `block_size`: 块大小
    /// - `total_blocks`: 总块数
    /// - `device_id`: 设备 ID
    ///
    /// # 返回
    /// Ext4 文件系统实例
    pub fn open(
        device: Arc<dyn BlockDriver>,
        block_size: usize,
        total_blocks: usize,
        device_id: usize,
    ) -> Result<Arc<Self>, FsError> {
        pr_info!("[Ext4] Opening Ext4 filesystem on block device");
        pr_info!(
            "[Ext4] Device block size: {}, total blocks: {}",
            block_size,
            total_blocks
        );

        // 创建适配器
        let adapter = Arc::new(BlockDeviceAdapter::new(device.clone(), block_size));

        // 预检 superblock，避免 ext4_rs 在坏镜像/错误读取时 panic
        validate_superblock(&adapter)?;

        // 使用 ext4_rs 打开文件系统
        // 注意：ext4_rs::Ext4::open 直接返回 Ext4，不返回 Result
        pr_info!("[Ext4] Calling ext4_rs::Ext4::open...");
        let ext4 = ext4_rs::Ext4::open(adapter);
        pr_info!("[Ext4] ext4_rs returned successfully");

        let ext4 = Arc::new(Mutex::new(ext4));

        let inode_caches = Arc::new(Ext4InodeCaches::new());
        let fs_id = device_id as u64;
        let page_cache = Arc::new(PageCache::new());

        // 创建根 inode (inode 号 2 是 Ext4 的根目录)
        let root = Arc::new(Ext4Inode::new(
            ext4.clone(),
            inode_caches,
            page_cache.clone(),
            fs_id,
            2,
        ));

        let fs = Arc::new(Ext4FileSystem {
            device,
            block_size,
            total_blocks,
            device_id,
            fs_id,
            ext4,
            page_cache,
            root,
        });

        pr_info!("[Ext4] Filesystem opened successfully");
        Ok(fs)
    }
}

fn validate_superblock(adapter: &BlockDeviceAdapter) -> Result<(), FsError> {
    const SUPERBLOCK_OFFSET: usize = 1024;
    const MAGIC_OFFSET: usize = 0x38;
    const BLOCKS_PER_GROUP_OFFSET: usize = 0x20;
    const EXT4_MAGIC: u16 = 0xEF53;

    let buf = adapter.read_offset(SUPERBLOCK_OFFSET);
    if buf.len() < MAGIC_OFFSET + 2 {
        crate::pr_err!("[Ext4] Superblock read too small: {}", buf.len());
        return Err(FsError::IoError);
    }
    let magic = u16::from_le_bytes([buf[MAGIC_OFFSET], buf[MAGIC_OFFSET + 1]]);
    if magic != EXT4_MAGIC {
        crate::pr_err!("[Ext4] Invalid ext4 magic: {:#x}", magic);
        return Err(FsError::InvalidArgument);
    }
    let blocks_per_group = u32::from_le_bytes([
        buf[BLOCKS_PER_GROUP_OFFSET],
        buf[BLOCKS_PER_GROUP_OFFSET + 1],
        buf[BLOCKS_PER_GROUP_OFFSET + 2],
        buf[BLOCKS_PER_GROUP_OFFSET + 3],
    ]);
    if blocks_per_group == 0 {
        crate::pr_err!("[Ext4] Invalid superblock: blocks_per_group=0");
        return Err(FsError::InvalidArgument);
    }
    Ok(())
}

impl FileSystem for Ext4FileSystem {
    fn fs_type(&self) -> &'static str {
        "ext4"
    }

    fn root_inode(&self) -> Arc<dyn Inode> {
        self.root.clone()
    }

    fn sync(&self) -> Result<(), FsError> {
        // 调用底层块设备的 flush 方法，将缓存刷新到磁盘
        if self.device.flush() {
            Ok(())
        } else {
            Err(FsError::IoError)
        }
    }

    fn statfs(&self) -> Result<StatFs, FsError> {
        let ext4 = self.ext4.lock();
        let sb = &ext4.super_block;

        Ok(StatFs {
            block_size: self.block_size,
            total_blocks: self.total_blocks,
            free_blocks: sb.free_blocks_count() as usize,
            available_blocks: sb.free_blocks_count() as usize,
            total_inodes: sb.inodes_count as usize,
            free_inodes: sb.free_inodes_count() as usize,
            fsid: self.device_id as u64,
            max_filename_len: 255, // EXT4_NAME_LEN
        })
    }
}

