    };

    /// Compatible 字符串到探测函数的映射表
    /// 键为设备的 compatible 字符串，值为对应的探测函数
    /// 用于在设备树中查找和初始化设备
    pub static ref DEVICE_TREE_REGISTRY: SpinLock<BTreeMap<&'static str, fn(&FdtNode)>> =
        SpinLock::new(BTreeMap::new());

    /// 设备树中断控制器映射表
    /// 键为中断控制器的 phandle，值为对应的中断控制器驱动程序
    /// 用于在设备树中查找和管理中断控制器
    pub static ref DEVICE_TREE_INTC: SpinLock<BTreeMap<u32, Arc<dyn IntcDriver>>> =
        SpinLock::new(BTreeMap::new());
}

/// 早期初始化: 只解析 CPU 数量和时钟频率
///
/// 此函数在堆分配器初始化之前调用,因此不能使用任何需要堆分配的操作。
pub fn early_init() {
    let mut cpus = FDT.cpus();
    let Some(first_cpu) = cpus.next() else {
        pr_warn!("[Device] No CPU found in device tree");
        return;
    };

    set_num_cpu(1 + cpus.count());
    let freq = cpu_clock_frequency(first_cpu).unwrap_or_else(|| {
        pr_warn!(
            "[Device] CPU timebase/clock frequency missing in device tree; using {} Hz",
            DEFAULT_CLOCK_FREQ
        );
        DEFAULT_CLOCK_FREQ
    });
    set_clock_freq(freq);
}

fn cpu_clock_frequency(cpu: fdt::standard_nodes::Cpu<'_, '_>) -> Option<usize> {
    cpu.property("timebase-frequency")
        .or_else(|| FDT.find_node("/cpus")?.property("timebase-frequency"))
        .or_else(|| cpu.property("clock-frequency"))
        .or_else(|| FDT.find_node("/cpus")?.property("clock-frequency"))
        .and_then(|prop| prop.as_usize())
}

/// 初始化设备树
pub fn init() {
    let model = FDT
        .root()
        .property("model")
        .and_then(|p| p.value.split(|b| *b == 0).next())
        .and_then(|s| core::str::from_utf8(s).ok())
        .unwrap_or("unknown");
    pr_info!("[Device] devicetree of {} is initialized", model);

    // 设置 NUM_CPU 和 CLOCK_FREQ
    early_init();
    pr_info!("[Device] now has {} CPU(s)", num_cpu());
    pr_info!("[Device] CLOCK_FREQ set to {} Hz", clock_freq());

    FDT.memory().regions().for_each(|region| {
        pr_info!(
            "[Device] Memory Region: Start = {:#X}, Size = {:#X}",
            region.starting_address as usize,
            { region.size.unwrap() }
        );
    });

    if let Some(bootargs) = FDT.chosen().bootargs()
        && !bootargs.is_empty()
    {
        pr_info!("Kernel cmdline: {}", bootargs);
        *CMDLINE.write() = String::from(bootargs);
    }

    // 首先初始化中断控制器
    walk_dt(&FDT, true);
    walk_dt(&FDT, false);
}

/// 遍历设备树，查找并初始化 virtio 设备
/// # 参数
/// * `fdt` - 设备树对象
fn walk_dt(fdt: &Fdt, intc_only: bool) {
    for node in fdt.all_nodes() {
        if let Some(compatible) = node.compatible()
            && node.property("interrupt-controller").is_some() == intc_only
        {
            pr_info!("[Device] Found device: {}", node.name);
            let registry = DEVICE_TREE_REGISTRY.lock();
            for c in compatible.all() {
                if let Some(f) = registry.get(c) {
                    f(&node);
                }
            }
        }
    }
}

/// 返回 DRAM 的起始物理地址与总大小（合并所有 memory.regions）
/// # 返回值
/// * `Option<(usize, usize)>` - 返回起始地址和大小的元组，如果没有有效的内存区域则返回 None
pub fn dram_info() -> Option<(usize, usize)> {
    let mut start = usize::MAX;
    let mut end = 0usize;

    for region in FDT.memory().regions() {
        let s = region.starting_address as usize;
        let size = region.size.unwrap_or(0);
        let e = s.saturating_add(size);
        if size == 0 {
            continue;
        }
        if s < start {
            start = s;
        }
        if e > end {
            end = e;
        }
    }

    if start < end {
        Some((start, end - start))
    } else {
        None
    }
}

