                if fork() == 0 {
                    print(b"Hello from child process!\n");
                    let argv = [
                        c"/home/user/bin/hello".as_ptr(),
                        core::ptr::null(),
                    ];
                    execve(
                        c"/home/user/bin/hello".as_ptr(),
                        argv.as_ptr(),
                        core::ptr::null(),
                    );
                } else {
                    print(b"Hello from parent process!\n");
                }
            }
            b"bug2" => {
                print(b"bug2\n");
                let id = fork();
                if id == 0 {
                    print(b"Hello from child process!\n");
                    exit(0);
                } else {
                    let mut s: i32 = 0;
                    waitpid(id, &mut s, 0);
                    print(b"Hello from parent process!\n");
                }
            }
            b"help" => print(b"Available commands: help, exit, bug1, bug2, shutdown, hello\n"),
            b"shutdown" => shutdown(),
            b"hello" => {
                // 使用 fork + execve 模式,避免替换 init 进程
                let pid = fork();
                if pid == 0 {
                    // 子进程: 执行 hello 程序
                    let argv = [
                        c"/home/user/bin/hello".as_ptr(),
                        core::ptr::null(),
                    ];
                    execve(
                        c"/home/user/bin/hello".as_ptr(),
                        argv.as_ptr(),
                        core::ptr::null(),
                    );
                    // 如果 execve 失败,退出子进程
                    print(b"Failed to execute hello\n");
                    exit(-1);
                } else {
                    // 父进程: 等待子进程完成
                    let mut status: i32 = 0;
                    waitpid(pid, &mut status, 0);
                }
            }
            b"fork" => {
                if fork() == 0 {
                    print(b"Hello from child process!\n");
                    exit(0);
                } else {
                    print(b"Hello from parent process!\n");
                }
            }
            _ => print(b"Unknown command\n"),
        }
    }
}

