    /// 低级系统调用接口
    /// 参数：
    /// - number: 系统调用号
    /// - ...: 可变数量的参数，最多6个
    ///   返回值：系统调用的返回值
    pub unsafe fn __syscall(number: usize, ...) -> isize;
}

/// 宏：简化系统调用的使用
/// Usage: syscall!(SYSCALL_NUM, [arg1, arg2, ...])
#[macro_export]
macro_rules! syscall {
    // 0 Arguments
    ($nr:expr) => ({
        let __sys_nr = $nr;
        // Safety: Calls assembly function (__syscall), which is marked unsafe.
        // We pass placeholders for unused arguments to align with the assembly stub's stack frame setup.
        unsafe {
            __syscall(__sys_nr, 0, 0, 0, 0, 0, 0)
        }
    });
    // 1 Argument
    ($nr:expr, $arg1:expr) => ({
        let __sys_nr = $nr;
        let __sys_arg1 = $arg1;
        unsafe {
            __syscall(__sys_nr, __sys_arg1, 0, 0, 0, 0, 0)
        }
    });
    // 2 Arguments
    ($nr:expr, $arg1:expr, $arg2:expr) => ({
        let __sys_nr = $nr;
        let __sys_arg1 = $arg1;
        let __sys_arg2 = $arg2;
        unsafe {
            __syscall(__sys_nr, __sys_arg1, __sys_arg2, 0, 0, 0, 0)
        }
    });
    // 3 Arguments
    ($nr:expr, $arg1:expr, $arg2:expr, $arg3:expr) => ({
        let __sys_nr = $nr;
        let __sys_arg1 = $arg1;
        let __sys_arg2 = $arg2;
        let __sys_arg3 = $arg3;
        unsafe {
            __syscall(__sys_nr, __sys_arg1, __sys_arg2, __sys_arg3, 0, 0, 0)
        }
    });
    // 4 Arguments
    ($nr:expr, $arg1:expr, $arg2:expr, $arg3:expr, $arg4:expr) => ({
        let __sys_nr = $nr;
        let __sys_arg1 = $arg1;
        let __sys_arg2 = $arg2;
        let __sys_arg3 = $arg3;
        let __sys_arg4 = $arg4;
        unsafe {
            __syscall(__sys_nr, __sys_arg1, __sys_arg2, __sys_arg3, __sys_arg4, 0, 0)
        }
    });
    // 5 Arguments
    ($nr:expr, $arg1:expr, $arg2:expr, $arg3:expr, $arg4:expr, $arg5:expr) => ({
        let __sys_nr = $nr;
        let __sys_arg1 = $arg1;
        let __sys_arg2 = $arg2;
        let __sys_arg3 = $arg3;
        let __sys_arg4 = $arg4;
        let __sys_arg5 = $arg5;
        unsafe {
            __syscall(__sys_nr, __sys_arg1, __sys_arg2, __sys_arg3, __sys_arg4, __sys_arg5, 0)
        }
    });
    // 6 Arguments
    ($nr:expr, $arg1:expr, $arg2:expr, $arg3:expr, $arg4:expr, $arg5:expr, $arg6:expr) => ({
        let __sys_nr = $nr;
        let __sys_arg1 = $arg1;
        let __sys_arg2 = $arg2;
        let __sys_arg3 = $arg3;
        let __sys_arg4 = $arg4;
        let __sys_arg5 = $arg5;
        let __sys_arg6 = $arg6;
        unsafe {
            __syscall(__sys_nr, __sys_arg1, __sys_arg2, __sys_arg3, __sys_arg4, __sys_arg5, __sys_arg6)
        }
    });
}

//! Tmpfs - 内存临时文件系统
//!
//! 该模块提供了一个**完全驻留在内存中的文件系统**，支持完整的 POSIX 语义。
//!
//! # 组件
//!
//! - [`TmpFs`] - 文件系统结构，实现 `FileSystem` trait
//! - [`TmpfsInode`](inode::TmpfsInode) - Inode 实现，管理文件/目录数据
//!
//! # 设计概览
//!
//! ## 内存管理
//!
//! - **按需分配**：文件数据页在写入时才分配，节省内存
//! - **容量限制**：可配置最大内存使用量，防止 OOM
//! - **自动回收**：文件删除时物理页自动归还
//!
//! ## 架构特点
//!
//! - **无 BlockDevice 层**：直接管理物理帧，性能更好
//! - **Arc 共享**：使用 `Arc` 实现多进程文件共享
//! - **Weak 父引用**：避免循环引用导致内存泄漏
//!
//! # 使用示例
//!
//! ```rust
//! use crate::fs::mount_tmpfs;
//!
//! // 挂载 64MB tmpfs 到 /tmp
//! mount_tmpfs("/tmp", 64)?;
//!
//! // 无限制大小
//! mount_tmpfs("/run", 0)?;
//! ```
//!
//! # 性能特点
//!
//! - **高吞吐**：纯内存操作，无磁盘 I/O
//! - **低延迟**：物理页直接访问，无需缓存管理
//! - **并发安全**：使用 `SpinLock` 保护共享数据

