            let pte_array = unsafe {
                core::slice::from_raw_parts(
                    ppn.start_addr().to_va().as_usize() as *const PageTableEntry,
                    512, // 每级页表有 512 个 PTE
                )
            };
            let pte = &pte_array[idx];

            if !pte.is_valid() {
                return None; // 无效 PTE
