    /// 创建一个新的 CPU 实例 (指定 CPU ID)
    pub fn new_with_id(cpu_id: usize) -> Self {
        Cpu {
            cpu_id,
            current_task: None,
            current_memory_space: None,
            idle_task: None,
        }
    }

    /// 切换当前任务
    /// # 参数
    /// * `task` - 要切换到的任务
    pub fn switch_task(&mut self, task: SharedTask) {
        // 切换当前任务，并在必要时切换到其地址空间
        self.current_task = Some(task.clone());
        if !task.lock().is_kernel_thread() {
            self.current_memory_space = task.lock().memory_space.clone();
            activate(
                self.current_memory_space
                    .as_ref()
                    .unwrap()
                    .lock()
                    .root_ppn(),
            );
        }

        // 同步 TrapFrame 的 cpu_ptr 指向当前 CPU，确保多核迁移后 trap_entry 恢复正确的 tp
        let tf_usize = {
            use core::sync::atomic::Ordering;
            task.lock().trap_frame_ptr.load(Ordering::SeqCst) as usize
        };
        crate::arch::on_task_switch(tf_usize, self as *const _ as usize);
    }

    /// 切换当前内存空间
    /// # 参数
    /// * `space` - 要切换到的内存空间
    pub fn switch_space(&mut self, space: Arc<SpinLock<MemorySpace>>) {
        self.current_memory_space = Some(space.clone());
        activate(space.lock().root_ppn());
    }
}

/// 获取当前 CPU 的引用 (可变)
///
/// # Safety
///
/// 调用者必须确保在访问期间禁用抢占 (防止任务迁移到其他 CPU)。
#[inline]
#[rustfmt::skip]
pub fn current_cpu() -> &'static
mut Cpu {
    CPUS.get_mut()
}

/// 获取指定 CPU 的引用 (只读)
///
/// 用于跨核访问，例如负载均衡时查看其他 CPU 的任务。
#[inline]
pub fn cpu_of(cpu_id: usize) -> &'static Cpu {
    CPUS.get_of(cpu_id)
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::{kassert, test_case};

    /// 测试 CPUS 初始化
    test_case!(test_cpus_initialization, {
        let num_cpu = num_cpu();
        for cpu_id in 0..num_cpu {
            let cpu = CPUS.get_of(cpu_id);
            kassert!(cpu.cpu_id == cpu_id);
        }
    });

    /// 测试 cpu_id() 函数
    test_case!(test_cpu_id, {
        use crate::sync::PreemptGuard;

        let _guard = PreemptGuard::new();
        let id = crate::arch::cpu_id();
        kassert!(id < num_cpu());
    });

    /// 测试 current_cpu() 函数
    test_case!(test_current_cpu, {
        use crate::sync::PreemptGuard;

        let _guard = PreemptGuard::new();
        let cpu = current_cpu();
        kassert!(cpu.cpu_id < num_cpu());
    });

    /// 测试 cpu_of() 函数
    test_case!(test_cpu_of, {
        let cpu0 = cpu_of(0);
        kassert!(cpu0.cpu_id == 0);

        let num_cpu = num_cpu();
        if num_cpu > 1 {
            let cpu1 = cpu_of(1);
            kassert!(cpu1.cpu_id == 1);
        }
    });

    /// 测试 PerCpu 数据独立性（多核场景）
    test_case!(test_per_cpu_independence, {
        use crate::sync::{PerCpu, PreemptGuard};
        use core::sync::atomic::{AtomicUsize, Ordering};

        let per_cpu: PerCpu<AtomicUsize> = PerCpu::new(|| AtomicUsize::new(0));

        // 在当前 CPU 上修改值
        {
            let _guard = PreemptGuard::new();
            let counter = per_cpu.get();
            counter.store(100, Ordering::Relaxed);
        }

        // 验证当前 CPU 的值
        {
            let _guard = PreemptGuard::new();
            let counter = per_cpu.get();
            kassert!(counter.load(Ordering::Relaxed) == 100);
        }

        // 验证其他 CPU 的值仍然是初始值
        let num_cpu = num_cpu();
        let current_id = {
            let _guard = PreemptGuard::new();
            crate::arch::cpu_id()
        };

        for cpu_id in 0..num_cpu {
            if cpu_id != current_id {
                let counter = per_cpu.get_of(cpu_id);
                kassert!(counter.load(Ordering::Relaxed) == 0);
            }
        }
    });

    /// 测试 PerCpu 的 new_with_id 初始化
    test_case!(test_per_cpu_with_id, {
        use crate::sync::PerCpu;

        let per_cpu: PerCpu<usize> = PerCpu::new_with_id(|cpu_id| cpu_id * 10);

        let num_cpu = num_cpu();
        for cpu_id in 0..num_cpu {
            let value = per_cpu.get_of(cpu_id);
            kassert!(*value == cpu_id * 10);
        }
    });
}

//! 定时器队列模块
//!
//! 该模块实现了一个简单的定时器队列，用于管理和调度定时任务。

use alloc::{collections::btree_map::BTreeMap, sync::Arc};

use crate::{kernel::SharedTask, sync::SpinLock, vfs::TimeSpec};

lazy_static::lazy_static! {
    /// 全局等待队列实例
    /// 使用硬件时钟周期数作为时间单位
    /// 在定时器触发时唤醒任务
    pub static ref TIMER_QUEUE: SpinLock<TimerQueue> = SpinLock::new(TimerQueue::new());
    /// 定时器队列
    /// 使用硬件时钟周期数作为时间单位
    /// 在定时器触发时向任务发送对应信号
    pub static ref TIMER: SpinLock<TimerEntries> = SpinLock::new(TimerEntries::new());
}

/// 定时器队列，用于管理定时任务
pub struct TimerQueue {
    /// 以触发时间为键，任务为值的有序映射
    queue: BTreeMap<usize, SharedTask>,
}

impl TimerQueue {
    /// 创建一个新的定时器队列
    pub fn new() -> Self {
        Self {
            queue: BTreeMap::new(),
        }
    }

    /// 向队列中添加一个定时任务
    /// # 参数:
    /// - `trigger_time`: 任务触发的时间点
    /// - `task`: 需要执行的任务
    pub fn push(&mut self, mut trigger_time: usize, task: SharedTask) {
        while self.queue.contains_key(&trigger_time) {
            trigger_time += 1;
        }
        self.queue.insert(trigger_time, task);
    }

    /// 弹出已到期的任务
    /// # 参数:
    /// - `current_time`: 当前时间点
    /// # 返回值:
    /// - 已到期的任务（如果有）
    pub fn pop_due_task(&mut self, current_time: usize) -> Option<SharedTask> {
        if let Some((&trigger_time, _)) = self.queue.iter().next()
            && trigger_time <= current_time
        {
            return self.queue.remove(&trigger_time);
        }
        None
    }

    /// 移除指定任务
    /// # 参数:
    /// - `task`: 需要移除的任务
    /// # 返回值:
    /// - 被移除的任务（如果存在）
    pub fn remove_task(&mut self, task: &SharedTask) -> Option<SharedTask> {
        let key = self.queue.iter().find_map(|(time, t)| {
            if Arc::ptr_eq(task, t) {
                Some(*time)
            } else {
                None
            }
        })?;
        self.queue.remove(&key)
    }
}

/// 定时器条目
pub struct TimerEntry {
    /// 信号编号
    pub sig: usize,
    /// 关联的任务
    pub task: SharedTask,
    /// 定时器周期
    pub it_interval: TimeSpec,
}

impl TimerEntry {
    /// 创建一个新的定时器条目
    pub fn new(sig: usize, task: SharedTask, it_interval: TimeSpec) -> Self {
        Self {
            sig,
            task,
            it_interval,
        }
    }
}

/// 定时器条目集合
pub struct TimerEntries {
    pub entries: BTreeMap<usize, TimerEntry>,
}

impl TimerEntries {
    /// 创建一个新的定时器条目集合
    pub fn new() -> Self {
        Self {
            entries: BTreeMap::new(),
        }
    }

    /// 向集合中添加一个定时器条目
    /// # 参数:
    /// - `trigger_time`: 触发时间点
    /// - `entry`: 定时器条目
    pub fn push(&mut self, mut trigger_time: usize, entry: TimerEntry) {
        while self.entries.contains_key(&trigger_time) {
            trigger_time += 1;
        }
        self.entries.insert(trigger_time, entry);
    }

    /// 弹出已到期的定时器条目
    /// # 参数:
    /// - `current_time`: 当前时间点
    /// # 返回值:
    /// - 已到期的定时器条目（如果有）
    pub fn pop_due_entry(&mut self, current_time: usize) -> Option<TimerEntry> {
        if let Some((&trigger_time, _)) = self.entries.iter().next()
            && trigger_time <= current_time
        {
            return self.entries.remove(&trigger_time);
        }
        None
    }

    /// 查找与指定任务关联的定时器条目
    /// # 参数:
    /// - `task`: 目标任务
    /// # 返回值:
    /// - 关联的定时器条目（如果存在）
    pub fn find_entry(&self, task: &SharedTask, sig: usize) -> Option<(&usize, &TimerEntry)> {
        for (time, entry) in self.entries.iter() {
            if Arc::ptr_eq(task, &entry.task) && entry.sig == sig {
                return Some((time, entry));
            }
        }
        None
    }

    /// 移除与指定任务关联的定时器条目
    /// # 参数:
    /// - `task`: 目标任务
    /// # 返回值:
    /// - 被移除的定时器条目（如果存在）
    pub fn remove_entry(&mut self, task: &SharedTask, sig: usize) -> Option<TimerEntry> {
        let key = self.find_entry(task, sig).map(|(time, _)| *time)?;
        self.entries.remove(&key)
    }
}
